"use client";

import { useSession, signOut } from "next-auth/react";
import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import axios from "axios";

// --- Types ---
interface ScanLog {
  type: "info" | "duplicate" | "clean";
  message?: string;
  issue_id?: number;
  match_id?: number;
  score?: number;
  title?: string;
  url?: string;
}

interface Repository {
  id: number;
  name: string;
  full_name: string;
  private: boolean;
}

export default function Dashboard() {
  const { data: session, status } = useSession();
  const router = useRouter();
  
  // State
  const [loading, setLoading] = useState(false);
  const [logs, setLogs] = useState<ScanLog[]>([]); 
  const [summary, setSummary] = useState("");
  const [repos, setRepos] = useState<Repository[]>([]);
  const [selectedRepo, setSelectedRepo] = useState<string>("");
  const [loadingRepos, setLoadingRepos] = useState(true);

  // Authentication Check
  useEffect(() => {
    if (status === "authenticated") fetchRepos();
    else if (status === "unauthenticated") router.push("/login");
  }, [status, router]);

  // Fetch Repositories
  const fetchRepos = async () => {
    try {
      const res = await axios.get("/api/repos");
      setRepos(res.data.repos);
      if (res.data.repos.length > 0) setSelectedRepo(res.data.repos[0].full_name); 
    } catch (error) {
      console.error(error);
      setSummary("SYSTEM ERROR: Failed to load repository list.");
    } finally {
      setLoadingRepos(false);
    }
  };

  // Scan Logic
  const handleScan = async () => {
    if (!selectedRepo) return;
    setLoading(true);
    setLogs([]); 
    setSummary(`Scanning ${selectedRepo}...`);
    try {
      const res = await axios.post("/api/scan", { repo_full_name: selectedRepo });
      setSummary(res.data.summary);
      setLogs(res.data.logs); 
    } catch (e: any) {
      console.error(e);
      setSummary(`Error: ${e.response?.data?.error || e.message}`);
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || loadingRepos) return <div style={{ padding: "20px" }}>Loading...</div>;

  // --- RAW HTML STRUCTURE (No Styling) ---
  return (
    <div style={{ padding: "40px", fontFamily: "sans-serif" }}>
      
      {/* 1. Header Section */}
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "40px", borderBottom: "1px solid #ccc", paddingBottom: "20px" }}>
        <h1>GitHelix Dashboard</h1>
        <div style={{ display: "flex", alignItems: "center", gap: "20px" }}>
          <span>Signed in as <strong>{session?.user?.name}</strong></span>
          <button 
            onClick={() => signOut({ callbackUrl: "/login" })}
            style={{ padding: "8px 16px", cursor: "pointer" }}
          >
            Sign Out
          </button>
        </div>
      </div>

      {/* 2. Controls Section */}
      <div style={{ marginBottom: "40px" }}>
        <h3>Select Repository</h3>
        <div style={{ display: "flex", gap: "10px", marginBottom: "20px" }}>
          <select 
            value={selectedRepo} 
            onChange={(e) => setSelectedRepo(e.target.value)}
            style={{ padding: "10px", fontSize: "16px", minWidth: "300px" }}
          >
            {repos.map((repo) => (
              <option key={repo.id} value={repo.full_name}>
                {repo.full_name}
              </option>
            ))}
          </select>

          <button 
            onClick={handleScan}
            disabled={loading || !selectedRepo}
            style={{ padding: "10px 20px", fontSize: "16px", cursor: "pointer" }}
          >
            {loading ? "Scanning..." : "Start Scan"}
          </button>
        </div>

        {summary && <div style={{ padding: "10px", background: "#f0f0f0" }}><strong>Status:</strong> {summary}</div>}
      </div>

      {/* 3. Results Section */}
      {logs.length > 0 && (
        <div>
          <h3>Scan Results</h3>
          <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
            {logs.map((log, index) => (
              <div 
                key={index} 
                style={{ 
                  border: "1px solid #ddd", 
                  padding: "15px", 
                  background: log.type === "duplicate" ? "#fff0f0" : "#f0fff4" 
                }}
              >
                {/* Clean Issue */}
                {log.type === "clean" && (
                  <div>
                    <strong>#{log.issue_id}</strong>: {log.title} <span style={{ color: "green" }}>(Clean)</span>
                  </div>
                )}

                {/* Duplicate Issue */}
                {log.type === "duplicate" && (
                  <div>
                    <div style={{ color: "red", fontWeight: "bold" }}>
                      ⚠️ Duplicate Detected: #{log.issue_id}
                    </div>
                    <div>{log.title}</div>
                    <div style={{ marginTop: "5px", fontSize: "0.9em" }}>
                      Matches closed issue <strong>#{log.match_id}</strong> ({log.score}% match)
                    </div>
                    <a href={log.url} target="_blank" style={{ display: "block", marginTop: "5px" }}>
                      View on GitHub
                    </a>
                  </div>
                )}
                
                {/* Info Log */}
                {log.type === "info" && <div>ℹ️ {log.message}</div>}
              </div>
            ))}
          </div>
        </div>
      )}

    </div>
  );
}